from flask import Flask, request, jsonify
import os
import json
import time
from hashlib import sha256

app = Flask(__name__)

CACHE_FILE = 'api_cache.json'
CACHE_EXPIRATION = 300  # 5 minutes

def load_cache():
    if os.path.exists(CACHE_FILE):
        with open(CACHE_FILE, 'r') as f:
            return json.load(f)
    return {}

def save_cache(cache_data):
    with open(CACHE_FILE, 'w') as f:
        json.dump(cache_data, f, ensure_ascii=False)

def cache_key(url, params):
    key_input = url + json.dumps(params, sort_keys=True)
    return sha256(key_input.encode()).hexdigest()

def is_cache_expired(entry):
    return (time.time() - entry['timestamp']) > CACHE_EXPIRATION

cache_data = load_cache()

@app.route('/api/expensive_endpoint', methods=['GET'])
def expensive_api():
    url = request.path
    params = request.args.to_dict()
    key = cache_key(url, params)
    
    if key in cache_data and not is_cache_expired(cache_data[key]):
        return jsonify(cache_data[key]['response'])

    # Simulate an expensive API call
    api_response = {"data": "This is expensive data", "params": params}
    
    # Store response in cache
    cache_data[key] = {
        'response': api_response,
        'timestamp': time.time()
    }
    save_cache(cache_data)
    
    return jsonify(api_response)

